import {
  extensions,
  extensionTags,
  extensionVersions,
  files,
} from "@/lib/db/schema";
import {
  buildExtensionOrder,
  buildExtensionWhere,
} from "@/lib/search/query";
import {
  PAGE_SIZE,
  pageOffset,
  type Filters,
} from "@/lib/validators/filters";

const listSelect = {
  id: extensions.id,
  slug: extensions.slug,
  category: extensions.category,
  badge: extensions.badge,
  scope: extensions.scope,
  funcCat: extensions.funcCat,
  subCat: extensions.subCat,
