import { z } from "zod";

const CATEGORIES = ["skills", "mcp", "slash", "plugins"] as const;
const SCOPES = ["personal", "org", "enterprise"] as const;
const FUNC_CATS = ["workTask", "business", "tools"] as const;
const FILTER_CHIPS = ["all", "trending", "new", "official", "free"] as const;
const SORTS = ["downloads", "stars", "recent"] as const;
const TAG_MATCHES = ["any", "all"] as const;

export const PAGE_SIZE = 24;

export const filtersSchema = z.object({
  q: z.string().trim().min(1).max(120).optional(),
  category: z.enum(CATEGORIES).optional(),
  scope: z.enum(SCOPES).optional(),
  funcCat: z.enum(FUNC_CATS).optional(),
  subCat: z.string().trim().min(1).max(40).optional(),
  l2: z.string().trim().min(1).max(40).optional(),
  // Department id (dotted-path) or the literal "__all" to disable the filter.
  dept: z.string().trim().min(1).max(120).optional(),
  tags: z.array(z.string().trim().min(1).max(40)).max(16).optional(),
  tagMatch: z.enum(TAG_MATCHES).optional(),
  filter: z.enum(FILTER_CHIPS).optional(),
  sort: z.enum(SORTS).optional(),
  page: z.coerce.number().int().min(1).max(1000).optional(),
});

export type Filters = z.infer<typeof filtersSchema>;

/**
 * Parse Next.js searchParams into typed Filters. Invalid input is dropped,
 * so a malformed URL silently falls back to "no filter" rather than 500ing.
 */
export function parseFilters(
  input: Record<string, string | string[] | undefined>,
): Filters {
  const tags = input.tags;
  const normalized = {
    ...input,
    tags:
      tags === undefined
        ? undefined
        : Array.isArray(tags)
          ? tags
          : tags.split(",").filter(Boolean),
  };
  const parsed = filtersSchema.safeParse(normalized);
  return parsed.success ? parsed.data : {};
}

export function pageOffset(page: number | undefined) {
  return ((page ?? 1) - 1) * PAGE_SIZE;
}

/**
 * Adapter from `URLSearchParams` (the runtime shape) to the `Record` shape
 * `parseFilters` consumes. Repeated keys (`?tags=a&tags=b`) accumulate into
 * an array; `serializeFilters` always emits comma-joined, but external
 * links may use the array form and the validator already handles both.
 */
export function searchParamsToInput(
  searchParams: URLSearchParams,
): Record<string, string | string[]> {
  const out: Record<string, string | string[]> = {};
  for (const [key, value] of searchParams.entries()) {
    const prev = out[key];
    if (prev === undefined) {
      out[key] = value;
    } else if (Array.isArray(prev)) {
      prev.push(value);
    } else {
      out[key] = [prev, value];
    }
  }
  return out;
}

/**
 * Inverse of `parseFilters`. Encodes typed filters back into URL search
 * params using the same conventions parseFilters consumes — comma-joined
 * arrays for `tags`, omitted keys for undefined / empty values.
 */
export function serializeFilters(filters: Partial<Filters>): URLSearchParams {
  const params = new URLSearchParams();
  for (const [key, value] of Object.entries(filters)) {
    if (value === undefined || value === "" || value === null) continue;
    if (Array.isArray(value)) {
      if (value.length > 0) params.set(key, value.join(","));
    } else {
      params.set(key, String(value));
    }
  }
  return params;
}

import { and, desc, eq, ilike, inArray, like, or, type SQL, sql } from "drizzle-orm";

import { MY_DEPT_ID } from "@/lib/data/departments"; // fallback for unauthenticated users
import { db } from "@/lib/db/client";
import { extensions, extensionTags } from "@/lib/db/schema";
import type { Filters } from "@/lib/validators/filters";

// Special token in the dept URL param meaning "show all departments".
const ALL_DEPTS = "__all";

/**
 * Compose a SQL WHERE expression from typed filters. Returns `undefined` when
 * no clauses are active so callers can omit `.where()` entirely.
 */
export function buildExtensionWhere(
  filters: Filters,
  fallbackDeptId?: string,
): SQL | undefined {
  const clauses = [
    // Always limit to published extensions.
    eq(extensions.visibility, "published"),

    filters.category ? eq(extensions.category, filters.category) : undefined,
    filters.scope ? eq(extensions.scope, filters.scope) : undefined,
    filters.funcCat ? eq(extensions.funcCat, filters.funcCat) : undefined,
    filters.subCat ? eq(extensions.subCat, filters.subCat) : undefined,
    filters.l2 ? eq(extensions.l2, filters.l2) : undefined,

    // Dotted-path descendant filter — uses idx_ext_dept_path (text_pattern_ops).
    // When no dept param is provided, fall back to the authenticated user's
    // defaultDeptId (passed in from the page via getSession), then to MY_DEPT_ID
    // for unauthenticated visitors.
    (() => {
      const dept = filters.dept ?? fallbackDeptId ?? MY_DEPT_ID;
      if (dept === ALL_DEPTS) return undefined;
      return or(
        eq(extensions.deptId, dept),
        like(extensions.deptId, `${dept}.%`),
      );
    })(),

    // Filter chips
    filters.filter === "trending"
      ? sql`${extensions.downloadsCount} > 50000`
      : undefined,
    filters.filter === "new" ? eq(extensions.badge, "new") : undefined,
    filters.filter === "official"
      ? eq(extensions.badge, "official")
      : undefined,
    filters.filter === "free"
      ? sql`${extensions.licenseSpdx} IS NOT NULL`
      : undefined,

    // FTS via tsvector (set weight A/B/C in the GENERATED column) with
    // pg_trgm ILIKE fallback for short queries and CJK substrings.
    filters.q
      ? or(
          sql`${extensions.searchVector} @@ websearch_to_tsquery('simple', ${filters.q})`,
          ilike(extensions.name, `%${filters.q}%`),
          ilike(extensions.nameZh, `%${filters.q}%`),
        )
      : undefined,

    // Tag filter via aggregating subquery — `any` matches if at least one tag
    // overlaps; `all` requires every selected tag to be present.
    filters.tags && filters.tags.length > 0
      ? inArray(
          extensions.id,
          db
            .select({ id: extensionTags.extensionId })
            .from(extensionTags)
            .where(inArray(extensionTags.tagId, filters.tags))
            .groupBy(extensionTags.extensionId)
            .having(
              filters.tagMatch === "all"
                ? sql`count(*) = ${filters.tags.length}`
                : sql`count(*) >= 1`,
            ),
        )
      : undefined,
  ].filter((c): c is SQL => Boolean(c));

  return clauses.length > 0 ? and(...clauses) : undefined;
}

export function buildExtensionOrder(sort: Filters["sort"]) {
  switch (sort) {
    case "stars":
      return [desc(extensions.starsAvg), desc(extensions.downloadsCount)];
    case "recent":
      return [desc(extensions.publishedAt), desc(extensions.createdAt)];
    case "downloads":
    default:
      return [desc(extensions.downloadsCount)];
  }
}

