            <div className="text-muted-foreground px-3 py-2 text-[12px]">
              {t("empty")}
            </div>
          )}
          {publishers.map((p) => (
            <Option
              key={p.id}
              active={active === p.id}
              onClick={() => pick(p.id)}
            >
              <span className="flex-1 truncate">{publisherLabel(p, locale)}</span>
              <span className="text-muted-foreground font-mono text-[11px]">
                {p.count}
              </span>
            </Option>
          ))}
        </div>
      </PopoverContent>
    </Popover>
  );
}

function Option({
  active,
  onClick,
  children,
}: {
  active: boolean;
  onClick: () => void;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      aria-pressed={active}
      className={cn(
        "mx-1 flex w-[calc(100%-0.5rem)] items-center gap-2 rounded-md px-2 py-1 text-left text-[12.5px] transition",
        active
          ? "bg-primary/10 text-primary font-semibold"
          : "text-foreground hover:bg-accent",
      )}
    >
      {children}
    </button>
  );
}

