1	import { redirect } from "next/navigation";
2	import { getTranslations } from "next-intl/server";
3	import { Package, Plus } from "lucide-react";
4	
5	import { getSession } from "@/lib/auth/session";
6	import { getMyExtensions } from "@/lib/actions/publish";
7	import { isResumable, rowAction } from "@/lib/publish/row-action";
8	import { Link } from "@/lib/i18n/navigation";
9	import { DiscardButton } from "@/components/publish/discard-button";
10	
11	export async function generateMetadata() {
12	  const t = await getTranslations("publish.dashboard");
13	  return { title: t("title") };
14	}
15	
16	export default async function PublishDashboardPage() {
17	  const session = await getSession();
18	  if (!session) redirect("/sign-in");
19	
20	  const t = await getTranslations("publish.dashboard");
21	  const exts = await getMyExtensions(session.user.id);
22	
23	  const visibilityLabel: Record<string, string> = {
24	    draft: t("statusDraft"),
25	    published: t("statusPublished"),
26	    archived: t("statusArchived"),
27	  };
28	
29	  const versionStatusLabel: Record<string, string> = {
30	    resume_upload: t("versionPendingUpload"),
31	    resume_submit: t("versionReadyToSubmit"),
32	    scanning: t("versionScanning"),
33	    ready: t("versionReady"),
34	    rejected: t("versionRejected"),
35	  };
36	
37	  return (
38	    <main className="mx-auto max-w-3xl px-6 py-10">
39	      <div className="flex items-center justify-between mb-8">
40	        <h1 className="font-display text-2xl font-semibold">{t("title")}</h1>
41	        <Link
42	          href="/publish/new"
43	          className="flex items-center gap-2 rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground hover:opacity-90 transition-opacity"
44	        >
45	          <Plus className="h-4 w-4" />
46	          {t("newButton")}
47	        </Link>
48	      </div>
49	
50	      {exts.length === 0 ? (
51	        <div className="border-border bg-card/40 mx-auto flex max-w-md flex-col items-center gap-3 rounded-xl border border-dashed p-12 text-center">
52	          <Package className="text-muted-foreground/50 size-9" />
53	          <h2 className="text-foreground text-base font-semibold">
54	            {t("emptyTitle")}
55	          </h2>
56	          <p className="text-muted-foreground max-w-xs text-[13px] leading-relaxed">
57	            {t("empty")}
58	          </p>
59	          <Link
60	            href="/publish/new"
61	            className="bg-primary text-primary-foreground hover:opacity-90 mt-1 inline-flex items-center gap-1.5 rounded-md px-4 py-2 text-[13px] font-semibold transition-opacity"
62	          >
63	            <Plus className="size-3.5" />
64	            {t("emptyCta")}
65	          </Link>
66	        </div>
67	      ) : (
68	        <ul className="space-y-3">
69	          {exts.map((ext) => {
70	            const action = rowAction(ext.latestStatus, ext.latestBundleFileId !== null);
71	            const resumable = isResumable(action);
72	            const visibility = visibilityLabel[ext.visibility] ?? ext.visibility;
73	            const versionLabel =
74	              action !== "none" ? versionStatusLabel[action] : null;
75	
76	            const body = (
77	              <>
78	                <div className="min-w-0 flex-1 truncate">
79	                  <span className="font-medium">{ext.name}</span>
80	                  <span className="ml-2 font-mono text-xs text-muted-foreground">
81	                    {ext.slug}
82	                  </span>
83	                  {versionLabel && (
84	                    <span className="ml-2 text-xs text-muted-foreground">
85	                      · {versionLabel}
86	                    </span>
87	                  )}
88	                </div>
89	                <span className="shrink-0 rounded-full border border-border px-2.5 py-0.5 text-xs text-muted-foreground">
90	                  {visibility}
91	                </span>
92	              </>
93	            );
94	
95	            return (
96	              <li
97	                key={ext.id}
98	                className={`rounded-xl border border-border bg-card transition-colors ${
99	                  resumable ? "hover:border-primary/60" : ""
